191	func (c *hugoBuilder) initMemProfile() {
192		if c.r.memprofile == "" {
193			return
194		}
195	
196		f, err := os.Create(c.r.memprofile)
197		if err != nil {
198			c.r.logger.Errorf("could not create memory profile: ", err)
199		}
200		defer f.Close()
201		runtime.GC() // get up-to-date statistics
202		if err := pprof.WriteHeapProfile(f); err != nil {
203			c.r.logger.Errorf("could not write memory profile: ", err)
204		}
205	}
