462	func (c *hugoBuilder) copyStaticTo(sourceFs *filesystems.SourceFilesystem) (uint64, error) {
463		infol := c.r.logger.InfoCommand("static")
464		publishDir := helpers.FilePathSeparator
465	
466		if sourceFs.PublishFolder != "" {
467			publishDir = filepath.Join(publishDir, sourceFs.PublishFolder)
468		}
469	
470		fs := &countingStatFs{Fs: sourceFs.Fs}
471	
472		syncer := fsync.NewSyncer()
473		c.withConf(func(conf *commonConfig) {
474			syncer.NoTimes = conf.configs.Base.NoTimes
475			syncer.NoChmod = conf.configs.Base.NoChmod
476			syncer.ChmodFilter = chmodFilter
477	
478			syncer.DestFs = conf.fs.PublishDirStatic
479			// Now that we are using a unionFs for the static directories
480			// We can effectively clean the publishDir on initial sync
481			syncer.Delete = conf.configs.Base.CleanDestinationDir
482		})
483	
484		syncer.SrcFs = fs
485	
486		if syncer.Delete {
487			infol.Logf("removing all files from destination that don't exist in static dirs")
488	
489			syncer.DeleteFilter = func(f fsync.FileInfo) bool {
490				name := f.Name()
491	
492				// Keep .gitignore and .gitattributes anywhere
493				if name == ".gitignore" || name == ".gitattributes" {
494					return true
495				}
496	
497				// Keep Hugo's original dot-directory behavior
498				return f.IsDir() && strings.HasPrefix(name, ".")
499			}
500		}
501		start := time.Now()
502	
503		// because we are using a baseFs (to get the union right).
504		// set sync src to root
505		err := syncer.Sync(publishDir, helpers.FilePathSeparator)
506		if err != nil {
507			return 0, err
508		}
509		loggers.TimeTrackf(infol, start, nil, "syncing static files to %s", publishDir)
510	
511		// Sync runs Stat 2 times for every source file.
512		numFiles := fs.statCounter / 2
513	
514		return numFiles, err
515	}
