1043	func (c *hugoBuilder) hugo() (*hugolib.HugoSites, error) {
1044		var h *hugolib.HugoSites
1045		if err := c.withConfE(func(conf *commonConfig) error {
1046			var err error
1047			h, err = c.r.HugFromConfig(conf)
1048			return err
1049		}); err != nil {
1050			return nil, err
1051		}
1052	
1053		if c.s != nil {
1054			// A running server, register the media types.
1055			for _, s := range h.Sites {
1056				s.RegisterMediaTypes()
1057			}
1058		}
1059		return h, nil
1060	}
