1131	func (c *hugoBuilder) rebuildSites(events []fsnotify.Event) (err error) {
1132		defer func() {
1133			c.errState.setBuildErr(err)
1134		}()
1135		if err := c.errState.buildErr(); err != nil {
1136			ferrs := herrors.UnwrapFileErrorsWithErrorContext(err)
1137			for _, err := range ferrs {
1138				events = append(events, fsnotify.Event{Name: err.Position().Filename, Op: fsnotify.Write})
1139			}
1140		}
1141		var h *hugolib.HugoSites
1142		h, err = c.hugo()
1143		if err != nil {
1144			return
1145		}
1146		err = h.Build(hugolib.BuildCfg{NoBuildLock: true, RecentlyTouched: c.visitedURLs, ErrRecovery: c.errState.wasErr()}, events...)
1147		return
1148	}
