1167	func (c *hugoBuilder) reloadConfig() error {
1168		c.r.resetLogs()
1169		c.r.configVersionID.Add(1)
1170	
1171		if err := c.withConfOrOldConfE(func(conf *commonConfig) error {
1172			oldConf := conf
1173			c.conf = nil
1174			newConf, err := c.r.ConfigFromConfig(configKey{counter: c.r.configVersionID.Load()}, conf)
1175			if err != nil {
1176				return err
1177			}
1178			sameLen := len(oldConf.configs.Languages) == len(newConf.configs.Languages)
1179			if !sameLen {
1180				if oldConf.configs.IsMultihost || newConf.configs.IsMultihost {
1181					return errors.New("multihost change detected, please restart server")
1182				}
1183			}
1184			c.conf = newConf
1185			return nil
1186		}); err != nil {
1187			return err
1188		}
1189	
1190		if c.onConfigLoaded != nil {
1191			if err := c.onConfigLoaded(true); err != nil {
1192				return err
1193			}
1194		}
1195	
1196		return nil
1197	}
