62	// Build builds all sites. If filesystem events are provided,
63	// this is considered to be a potential partial rebuild.
64	func (h *HugoSites) Build(config BuildCfg, events ...fsnotify.Event) error {
65		if h.isRebuild() && !h.Conf.Watching() && !h.Conf.Running() {
66			return errors.New("Build called multiple times when not in watch or server mode (typically with hugolib.Test(t, files).Build(); Build() is already called once by Test)")
67		}
68		if !h.isRebuild() && terminal.PrintANSIColors(os.Stdout) {
69			// Don't show progress for fast builds.
70			d := debounce.New(250 * time.Millisecond)
71			d(func() {
72				h.progressReporter.Start()
73				h.reportProgress(func() (state terminal.ProgressState, progress float64) {
74					// We don't know how many files to process below, so use the intermediate state as the first progress.
75					return terminal.ProgressIntermediate, 1.0
76				})
77			})
78			defer d(func() {})
79		}
80	
81		infol := h.Log.InfoCommand("build")
82		defer loggers.TimeTrackf(infol, time.Now(), nil, "")
83		defer func() {
84			h.reportProgress(func() (state terminal.ProgressState, progress float64) {
85				return terminal.ProgressHidden, 1.0
86			})
87			h.BuildState.BuildCounter.Add(1)
88		}()
89	
90		if h.Deps == nil {
91			panic("must have deps")
92		}
93	
94		if !config.NoBuildLock {
95			unlock, err := h.BaseFs.LockBuild()
96			if err != nil {
97				return fmt.Errorf("failed to acquire a build lock: %w", err)
98			}
99			defer unlock()
100		}
101	
102		defer func() {
103			for _, s := range h.Sites {
104				s.Deps.BuildEndListeners.Notify()
105			}
106		}()
107	
108		errCollector := h.StartErrorCollector()
109		errs := make(chan error)
110	
111		go func(from, to chan error) {
112			var errors []error
113			i := 0
114			for e := range from {
115				i++
116				if i > 50 {
117					break
118				}
119				errors = append(errors, e)
120			}
121			to <- h.filterAndJoinErrors(errors)
122	
123			close(to)
124		}(errCollector, errs)
125	
126		for _, s := range h.Sites {
127			s.state = siteStateInit
128		}
129	
130		if h.Metrics != nil {
131			h.Metrics.Reset()
132		}
133	
134		h.buildCounters = config.testCounters
135		if h.buildCounters == nil {
136			h.buildCounters = &buildCounters{}
137		}
138	
139		// Need a pointer as this may be modified.
140		conf := &config
141		if conf.WhatChanged == nil {
142			// Assume everything has changed
143			conf.WhatChanged = &WhatChanged{needsPagesAssembly: true}
144		}
145	
146		var prepareErr error
147	
148		if !config.PartialReRender {
149			prepare := func() error {
150				init := func(conf *BuildCfg) error {
151					for _, s := range h.Sites {
152						s.Deps.BuildStartListeners.Notify()
153					}
154	
155					if len(events) > 0 || len(conf.WhatChanged.Changes()) > 0 {
156						// Rebuild
157						if err := h.initRebuild(conf); err != nil {
158							return fmt.Errorf("initRebuild: %w", err)
159						}
160					} else {
161						if err := h.initSites(); err != nil {
162							return fmt.Errorf("initSites: %w", err)
163						}
164					}
165	
166					return nil
167				}
168	
169				ctx := context.Background()
170	
171				if err := h.process(ctx, infol, conf, init, events...); err != nil {
172					return fmt.Errorf("process: %w", err)
173				}
174				h.reportProgress(func() (state terminal.ProgressState, progress float64) {
175					return terminal.ProgressNormal, 0.15
176				})
177				if err := h.assemble(ctx, infol, conf); err != nil {
178					return fmt.Errorf("assemble: %w", err)
179				}
180				h.reportProgress(func() (state terminal.ProgressState, progress float64) {
181					return terminal.ProgressNormal, 0.20
182				})
183	
184				return nil
185			}
186	
187			if prepareErr = prepare(); prepareErr != nil {
188				h.SendError(prepareErr)
189			}
190		}
191	
192		for s := range h.allSites(nil) {
193			s.state = siteStateReady
194		}
195	
196		if prepareErr == nil {
197			if err := h.render(infol, conf); err != nil {
198				h.SendError(fmt.Errorf("render: %w", err))
199			}
200	
201			// Make sure to write any build stats to disk first so it's available
202			// to the post processors.
203			if err := h.writeBuildStats(); err != nil {
204				return err
205			}
206	
207			// We need to do this before render deferred.
208			if err := h.printPathWarningsOnce(); err != nil {
209				h.SendError(fmt.Errorf("printPathWarnings: %w", err))
210			}
211	
212			if err := h.renderDeferred(infol); err != nil {
213				h.SendError(fmt.Errorf("renderDeferred: %w", err))
214			}
215	
216			// This needs to be done after the deferred rendering to get complete template usage coverage.
217			if err := h.printUnusedTemplatesOnce(); err != nil {
218				h.SendError(fmt.Errorf("printPathWarnings: %w", err))
219			}
220	
221			if err := h.postProcess(infol); err != nil {
222				h.SendError(fmt.Errorf("postProcess: %w", err))
223			}
224		}
225	
226		if h.Metrics != nil {
227			var b bytes.Buffer
228			h.Metrics.WriteMetrics(&b)
229	
230			h.Log.Printf("\nTemplate Metrics:\n\n")
231			h.Log.Println(b.String())
232		}
233	
234		h.StopErrorCollector()
235	
236		err := <-errs
237		if err != nil {
238			return err
239		}
240	
241		if err := h.fatalErrorHandler.getErr(); err != nil {
242			return err
243		}
244	
245		errorCount := h.Log.LoggCount(logg.LevelError) + loggers.Log().LoggCount(logg.LevelError)
246		if errorCount > 0 {
247			return fmt.Errorf("logged %d error(s)", errorCount)
248		}
249	
250		return nil
251	}
